userText = ""
def pre_assign(text, userKey=0):
    from itertools import cycle
    cycle_it = cycle(str(userKey))
    list_char,list_num = [],[]
    for char in text:
        num = next(cycle_it)
        list_char.append(char)
        list_num.append(num)
    return list_char, list_num

def assign(text, userKey):
    from itertools import cycle
    cycle_it = cycle(userKey)
    list_char,list_num = [],[]
    for char in text:
        num = next(cycle_it)
        list_char.append(char)
        list_num.append(num)
    return list_char, list_num

